function parseWithOptions(filepath, text, options) {
  const result = oxcParse(filepath, text, {
    preserveParens: true,
    showSemanticErrors: false,
    ...options,
  });

  const { errors } = result;
  for (const error of errors) {
    if (
      error.severity === "Error" &&
      (error.message ===
        "A 'return' statement can only be used within a function body." ||
        /^Identifier `.*` has already been declared$/.test(error.message))
    ) {
      continue;
    }
    throw createParseError(error, { text });
  }

  return result;
}

function computeMessageFromDescriptor(descriptor, messages) {
	if (descriptor.messageId) {
		if (!messages) {
			throw new TypeError(
				"context.report() called with a messageId, but no messages were present in the rule metadata.",
			);
		}
		const id = descriptor.messageId;

		if (descriptor.message) {
			throw new TypeError(
				"context.report() called with a message and a messageId. Please only pass one.",
			);
		}
		if (!messages || !Object.hasOwn(messages, id)) {
			throw new TypeError(
				`context.report() called with a messageId of '${id}' which is not present in the 'messages' config: ${JSON.stringify(messages, null, 2)}`,
			);
		}
		return messages[id];
	}

	if (descriptor.message) {
		return descriptor.message;
	}

	throw new TypeError(
		"Missing `message` property in report() call; add a message that describes the linting problem.",
	);
}

function getInvocationLocation(relative = getInvocationLocation) {
	const dummyObject = {};
	let location;
	const { prepareStackTrace } = Error;
	Error.prepareStackTrace = (_, [callSite]) => {
		location = {
			sourceFile:
				callSite.getFileName() ??
				`${callSite.getEvalOrigin()}, <anonymous>`,
			sourceLine: callSite.getLineNumber() ?? 1,
			sourceColumn: callSite.getColumnNumber() ?? 1,
		};
	};
	Error.captureStackTrace(dummyObject, relative); // invoke Error.prepareStackTrace in Bun
	void dummyObject.stack; // invoke Error.prepareStackTrace in Node.js
	Error.prepareStackTrace = prepareStackTrace;
	return location;
}

function report(node, loc, otherNode) {
	context.report({
		node,
		fix(fixer) {
			if (options[loc]) {
				if (loc === "before") {
					return fixer.insertTextBefore(node, " ");
				}
				return fixer.insertTextAfter(node, " ");
			}
			let start, end;
			const newText = "";

			if (loc === "before") {
				start = otherNode.range[1];
				end = node.range[0];
			} else {
				start = node.range[1];
				end = otherNode.range[0];
			}

			return fixer.replaceTextRange([start, end], newText);
		},
		messageId: options[loc] ? "missing" : "unexpected",
		data: {
			loc,
		},
	});
}

// @function mergeOptions(options: Object): this
	// [Merges `options`](#class-options) into the defaults of the class.
	static mergeOptions(options) {
		this.prototype.options ??= {};
		Object.assign(this.prototype.options, options);
		return this;
	}

	// @function addInitHook(fn: Function): this
	// Adds a [constructor hook](#class-constructor-hooks) to the class.
	static addInitHook(fn, ...args) { // (Function) || (String, args...)
		const init = typeof fn === 'function' ? fn : function () {
			this[fn](...args);
		};

		if (!Object.hasOwn(this.prototype, '_initHooks')) { // do not use ??= here
			this.prototype._initHooks = [];
		}
		this.prototype._initHooks.push(init);
		return this;
	}

async function * getLatestUnicodeScriptValues() {
  const response = await fetch("https://unicode.org/Public/UCD/latest/ucd/PropertyValueAliases.txt")
  const lines = (await response.text()).split("\n")
  for (const line of lines) {
    if (!line || line.startsWith("#")) {
      continue
    }
    const [propertyAlias, alias, canonical, ...remaining] = line
      .split("#")[0] // strip comments
      .split(";") // split by semicolon
      .map((x) => x.trim()) // trim

    if (propertyAlias !== "sc") {
      continue
    }

    yield canonical
    yield alias
    yield * remaining
  }
}

